#!/usr/bin/env python3"""📊 回测系统 v3 — 统一回测框架整合全部策略 + 参数搜索 + 权益曲线 + 归因分析 + 敏感性分析"""import sys, os, json, subprocess, mathfrom pathlib import Pathfrom datetime import datetimeimport pandas as pdimport numpy as npimport sys, os, subprocess as _bridge_shif 'msys64' in sys.executable:    _bridge_sh.run(['C:/Python314/python.exe'] + sys.argv)    sys.exit(0)HERE = Path(__file__).resolve().parentsys.path.insert(0, str(HERE))from strategy_v4 import DataSource, Indicators, Backtest as OldBacktest# ==================== 数据获取 ====================class DataFetcher:    """统一数据源"""    def __init__(self):    self.ds = DataSource()    self._cache = {}    def get(self, symbol, days=500):    if symbol in self._cache:            return self._cache[symbol]    df = self.ds.get_kline(symbol, days)    if df is not None:            self._cache[symbol] = df    return df    def get_multi(self, symbols, days=500):    return {s: self.get(s, days) for s in symbols}# ==================== 回测引擎 ====================class BacktestEngine:    """统一回测引擎 — 支持所有策略类型、参数搜索、分段回测"""    # === 策略定义 ===    STRATEGIES = {}    @classmethod    def register(cls, name, func):    cls.STRATEGIES[name] = func    @staticmethod    def _prepare(df):    d = df.copy()    # 基础指标    d['ma5'] = d['close'].rolling(5).mean()    d['ma10'] = d['close'].rolling(10).mean()    d['ma14'] = d['close'].rolling(14).mean()    d['ma18'] = d['close'].rolling(18).mean()    d['ma20'] = d['close'].rolling(20).mean()    d['ma60'] = d['close'].rolling(60).mean()    # 布林带    d['bb_mid'], d['bb_up'], d['bb_low'] = Indicators.Bollinger(d, 20, 2)    d['bb_pos'] = (d['close'] - d['bb_low']) / (d['bb_up'] - d['bb_low']).replace(0, np.nan) * 100    # RSI    d['rsi14'] = Indicators.RSI(d, 14)    # KDJ    d['kdj_k'], d['kdj_d'], d['kdj_j'] = Indicators.KDJ(d, 9)    # MACD    d['macd_dif'], d['macd_dea'], d['macd'] = Indicators.MACD(d)    # ATR    d['atr14'] = Indicators.ATR(d, 14)    # 量比    d['vol_ratio'] = Indicators.VolumeRatio(d, 20)    return d    @staticmethod    def _loop(df_prep, buy_func, sell_func, stop_loss=None):    """通用回测循环"""    d = df_prep.copy()    d['signal'] = 0; d['position'] = 0    pos = False; entry_price = 0    peak = 0    d['entry_price'] = 0.0    for i in range(len(d)):            if not pos:                if buy_func(d, i):                    pos = True                    entry_price = d['close'].iloc[i]                    peak = entry_price                    d.loc[d.index[i], 'signal'] = 1                    d.loc[d.index[i], 'entry_price'] = entry_price            else:                # 追踪止损：从最高点回撤                if d['close'].iloc[i] > peak:                    peak = d['close'].iloc[i]                should_sell = sell_func(d, i)                if stop_loss:                    trail_pct = 0.08 if isinstance(stop_loss, dict) and stop_loss.get('trailing') else stop_loss                    # 硬止损                    if isinstance(stop_loss, dict):                        hard_stop = stop_loss.get('hard', 0)                        trailing = stop_loss.get('trailing', 0)                        if hard_stop > 0 and (d['close'].iloc[i] - entry_price) / entry_price < -hard_stop:                            should_sell = True                        if trailing > 0 and (d['close'].iloc[i] - peak) / peak < -trailing:                            should_sell = True                    else:                        if (d['close'].iloc[i] - entry_price) / entry_price < -stop_loss:                            should_sell = True                if should_sell:                    pos = False                    d.loc[d.index[i], 'signal'] = -1            d.loc[d.index[i], 'position'] = 1 if pos else 0    d['sr'] = d['position'].shift(1) * d['return']    d['sr'] = d['sr'].fillna(0)    d['cum'] = (1 + d['sr']).cumprod()    d['cum_bh'] = (1 + d['return']).cumprod()    return d    # === 策略集合 ===    @staticmethod    def strat_ma_cross(df_prep, params):    """MA金叉死叉"""    fast = params.get('fast', 5)    slow = params.get('slow', 20)    def buy(d, i):            return d['ma14'].iloc[i] > d['ma18'].iloc[i] if fast == 14 else d['close'].rolling(fast).mean().iloc[i] > d['close'].rolling(slow).mean().iloc[i]    def sell(d, i):            return d['ma14'].iloc[i] < d['ma18'].iloc[i] if fast == 14 else d['close'].rolling(fast).mean().iloc[i] < d['close'].rolling(slow).mean().iloc[i]    # 重算MA    d = df_prep.copy()    d['ma_f'] = d['close'].rolling(fast).mean()    d['ma_s'] = d['close'].rolling(slow).mean()    return BacktestEngine._loop(d,            lambda d,i: d['ma_f'].iloc[i] > d['ma_s'].iloc[i],            lambda d,i: d['ma_f'].iloc[i] < d['ma_s'].iloc[i],            params.get('stop_loss'))    @staticmethod    def strat_bollinger(df_prep, params):    """布林带反转"""    period = params.get('period', 20)    k = params.get('k', 2)    d = df_prep.copy()    d['bb_mid2'], d['bb_up2'], d['bb_low2'] = Indicators.Bollinger(d, period, k)    d['bb_w'] = (d['bb_up2'] - d['bb_low2']) / d['bb_mid2'] * 100    return BacktestEngine._loop(d,            lambda d,i: d['low'].iloc[i] <= d['bb_low2'].iloc[i] and d['bb_w'].iloc[i] > 2,            lambda d,i: d['close'].iloc[i] >= d['bb_mid2'].iloc[i],            params.get('stop_loss'))    @staticmethod    def strat_rsi(df_prep, params):    """RSI均值回归"""    period = params.get('period', 14)    oversold = params.get('oversold', 30)    overbought = params.get('overbought', 70)    d = df_prep.copy()    d['rsi_ind'] = Indicators.RSI(d, period)    return BacktestEngine._loop(d,            lambda d,i: d['rsi_ind'].iloc[i] < oversold,            lambda d,i: d['rsi_ind'].iloc[i] > overbought,            params.get('stop_loss'))    @staticmethod    def strat_kdj(df_prep, params):    """KDJ超买超卖"""    d = df_prep.copy()    return BacktestEngine._loop(d,            lambda d,i: d['kdj_k'].iloc[i] < 20,            lambda d,i: d['kdj_k'].iloc[i] > 80,            params.get('stop_loss'))    @staticmethod    def strat_macd(df_prep, params):    """MACD金叉死叉"""    d = df_prep.copy()    return BacktestEngine._loop(d,            lambda d,i: i > 0 and d['macd'].iloc[i-1] < 0 and d['macd'].iloc[i] > 0,            lambda d,i: i > 0 and d['macd'].iloc[i-1] > 0 and d['macd'].iloc[i] < 0,            params.get('stop_loss'))    @staticmethod    def strat_fusion1(df_prep, params):    """融合：MA14/18金叉+RSI过滤+布林中轨"""    d = df_prep.copy()    stop = params.get('stop_loss', 0.05)    return BacktestEngine._loop(d,            lambda d,i: d['ma14'].iloc[i] > d['ma18'].iloc[i] and d['rsi14'].iloc[i] < 70 and d['close'].iloc[i] <= d['bb_mid'].iloc[i] * 1.02,            lambda d,i: d['ma14'].iloc[i] < d['ma18'].iloc[i] or d['rsi14'].iloc[i] > 80,            stop)    @staticmethod    def strat_fusion2(df_prep, params):    """融合：布林触底+KDJ+RSI"""    d = df_prep.copy()    stop = params.get('stop_loss', 0.05)    return BacktestEngine._loop(d,            lambda d,i: d['low'].iloc[i] <= d['bb_low'].iloc[i] and d['kdj_k'].iloc[i] < 25 and d['rsi14'].iloc[i] < 40,            lambda d,i: d['close'].iloc[i] >= d['bb_mid'].iloc[i] or d['kdj_j'].iloc[i] > 100,            stop)    @staticmethod    def strat_fusion3(df_prep, params):    """融合：三确认(MA+RSI+BB+MACD)"""    d = df_prep.copy()    return BacktestEngine._loop(d,            lambda d,i: d['ma14'].iloc[i] > d['ma18'].iloc[i] and d['rsi14'].iloc[i] > 50 and d['close'].iloc[i] > d['bb_mid'].iloc[i] and d['macd_dif'].iloc[i] > d['macd_dea'].iloc[i],            lambda d,i: d['ma14'].iloc[i] < d['ma18'].iloc[i] or d['rsi14'].iloc[i] > 85 or d['close'].iloc[i] < d['bb_mid'].iloc[i],            None)    # === 分析 ===    @staticmethod    def analyze(result):    """全面回测指标"""    d = result.copy()    total = d['cum'].iloc[-1] - 1    bh = d['cum_bh'].iloc[-1] - 1    years = len(d) / 252    annual = (1 + total) ** (1 / years) - 1 if years > 0 else 0    excess = d['sr'] - 0.02/252    sharpe = np.sqrt(252) * excess.mean() / excess.std() if excess.std() > 0 else 0    cum_max = d['cum'].cummax()    mdd = (d['cum'] / cum_max - 1).min()    calmar = annual / abs(mdd) if mdd != 0 else 0    cagr = annual    # α 计算（年化超额 vs 无风险基准2%）    alpha = annual - 0.02    # 交易分析    trades = d[d['signal'] != 0].copy()    # 配对买入/卖出    buys = trades[trades['signal'] == 1]    sells = trades[trades['signal'] == -1]    n_buys = len(buys)    n_sells = len(sells)    # 每笔交易收益    trade_returns = []    for i in range(min(n_buys, n_sells)):            buy_idx = buys.index[i]            sell_idx = sells.index[i]            tr = (d.loc[sell_idx, 'close'] - d.loc[buy_idx, 'close']) / d.loc[buy_idx, 'close']            trade_returns.append(tr)    trade_series = pd.Series(trade_returns) if trade_returns else pd.Series([], dtype=float)    win_trades = (trade_series > 0).sum()    loss_trades = (trade_series < 0).sum()    wr = win_trades / len(trade_series) if len(trade_series) > 0 else 0    avg_win = trade_series[trade_series > 0].mean() if win_trades > 0 else 0    avg_loss = abs(trade_series[trade_series < 0].mean()) if loss_trades > 0 else 0    profit_factor = (trade_series[trade_series > 0].sum() / abs(trade_series[trade_series < 0].sum())) if loss_trades > 0 and abs(trade_series[trade_series < 0].sum()) > 0 else 0    avg_trade = trade_series.mean() if len(trade_series) > 0 else 0    # 连续亏损    if len(trade_series) > 0:            consec_loss = 0            max_consec_loss = 0            for tr in trade_series:                if tr < 0:                    consec_loss += 1                    max_consec_loss = max(max_consec_loss, consec_loss)                else:                    consec_loss = 0    else:            max_consec_loss = 0    # 月胜率    monthly = d.set_index('date').resample('ME')['sr'].sum().dropna()    win_months = (monthly > 0).sum()    total_months = len(monthly)    # 周胜率    weekly = d.set_index('date').resample('W')['sr'].sum().dropna()    win_weeks = (weekly > 0).sum()    total_weeks = len(weekly)    return {            '总收益率': f"{total*100:.2f}%",            '买入持有': f"{bh*100:.2f}%",            '超额收益': f"{(total-bh)*100:+.2f}%",            '年化': f"{annual*100:.2f}%",            '夏普': round(sharpe, 3),            '最大回撤': f"{mdd*100:.2f}%",            '卡玛比': round(calmar, 2),            '年化α': f"{alpha*100:+.2f}%",            '胜率(交易)': f"{wr*100:.1f}%",            '盈亏比': f"{avg_win/avg_loss:.2f}" if avg_loss > 0 else "N/A",            '利润因子': f"{profit_factor:.2f}",            '平均单笔': f"{avg_trade*100:.2f}%",            '最大连亏': f"{max_consec_loss}次",            '月胜率': f"{win_months}/{total_months} ({win_months/total_months*100:.0f}%)" if total_months else "N/A",            '周胜率': f"{win_weeks}/{total_weeks} ({win_weeks/total_weeks*100:.0f}%)" if total_weeks else "N/A",            '开仓次数': n_buys,            '持仓天数': int((d['position'] == 1).sum()),            # 净值            'final_nav': round(d['cum'].iloc[-1], 4),            'bh_nav': round(d['cum_bh'].iloc[-1], 4),    }# ==================== 参数搜索 ====================class ParamSearch:    """参数扫描优化"""    @staticmethod    def scan(df_prep, strategy_func, param_grid):    """网格搜索最优参数"""    results = []    for params in param_grid:            d = strategy_func(df_prep, params)            m = BacktestEngine.analyze(d)            results.append((params, m))    return results    @staticmethod    def top_n(results, n=10, metric='总收益率', reverse=True):    """按指标排序取TopN"""    def get_val(m, key):            v = m[key]            if isinstance(v, str):                return float(v.replace('%','').replace('+',''))            return v    ranked = sorted(results, key=lambda x: get_val(x[1], metric), reverse=reverse)    return ranked[:n]# ==================== 报告输出 ====================class BacktestReport:    """格式化回测报告"""    @staticmethod    def brief(df_prep, name="策略"):    """回测并输出简介"""    bte = BacktestEngine    # 定义所有策略    strategies = [            ("MA金叉 MA5/20", bte.strat_ma_cross, {'fast':5,'slow':20}),            ("MA金叉 MA14/18", bte.strat_ma_cross, {'fast':14,'slow':18}),            ("布林带反转 20/2", bte.strat_bollinger, {'period':20,'k':2}),            ("布林带反转 20/2.5", bte.strat_bollinger, {'period':20,'k':2.5}),            ("KDJ超买超卖", bte.strat_kdj, {}),            ("RSI均值回归 14/30/70", bte.strat_rsi, {'period':14,'oversold':30,'overbought':70}),            ("MACD金叉死叉", bte.strat_macd, {}),            ("融合1: MA14/18+布林中轨+RSI", bte.strat_fusion1, {'stop_loss':0.05}),            ("融合2: 布林触底+KDJ共振", bte.strat_fusion2, {'stop_loss':0.05}),            ("融合3: 三确认", bte.strat_fusion3, {}),    ]    results = []    for sname, func, params in strategies:            d = func(df_prep, params)            m = bte.analyze(d)            results.append((sname, m))    # 输出    print(f"\n{'='*70}")    print(f"📊 {name}")    print(f"{'='*70}")    # 表头    print(f"{'策略':<28} {'总收益':>8} {'年化':>8} {'夏普':>6} {'回撤':>8} {'胜率':>5} {'盈亏比':>7} {'交易':>5}")    print(f"{'-'*28} {'-'*8} {'-'*8} {'-'*6} {'-'*8} {'-'*5} {'-'*7} {'-'*5}")    for sname, m in results:            total = m.get('总收益率', 'N/A')            ann = m.get('年化', 'N/A')            sh = m.get('夏普', 0)            mdd = m.get('最大回撤', 'N/A')            wr = m.get('胜率(交易)', 'N/A')            pf = m.get('利润因子', 'N/A')            trades = m.get('开仓次数', 0)            print(f"{sname:<28} {total:>8} {ann:>8} {sh:>5} {mdd:>8} {wr:>5} {pf:>6} {trades:>4}次")    # 排名    sort_keys = ['夏普', '总收益率', '年化', '利润因子']    for sk in sort_keys:            ranked = sorted(results, key=lambda x: BacktestReport._val(x[1], sk), reverse=True)            print(f"\n🏆 按{sk}排名: " + " → ".join([f"{s}({BacktestReport._val(m, sk)})" for s, m in ranked[:3]]))    return results    @staticmethod    def _val(m, key):    v = m.get(key, 0)    if isinstance(v, str):            try: return float(v.replace('%','').replace('+',''))            except: return 0    return v    @staticmethod    def full(df_prep, name, strategy_name, strategy_func, params):    """完整回测报告"""    d = strategy_func(df_prep, params)    m = BacktestEngine.analyze(d)    print(f"\n{'='*70}")    print(f"📊 {name} — {strategy_name}")    print(f"{'='*70}")    print(f"  {m['总收益率']} | 年化 {m['年化']} | 夏普 {m['夏普']}")    print(f"  回撤 {m['最大回撤']} | 买入持有 {m['买入持有']}")    print(f"  α {m['年化α']} | 卡玛比 {m['卡玛比']} | 利润因子 {m['利润因子']}")    print(f"  交易 {m['开仓次数']}次 | 胜率 {m['胜率(交易)']} | 盈亏比 {m['盈亏比']}")    print(f"  月胜率 {m['月胜率']} | 周胜率 {m['周胜率']} | 最大连亏 {m['最大连亏']}")    print(f"  平均单笔 {m['平均单笔']} | 持仓 {m['持仓天数']}天")    # 分段回测（前后各半）    half = len(df_prep) // 2    d_half1 = df_prep.iloc[:half].reset_index(drop=True)    d_half1['return'] = d_half1['close'].pct_change()    d_half2 = df_prep.iloc[half:].reset_index(drop=True)    d_half2['return'] = d_half2['close'].pct_change()    print(f"\n📈 分段表现:")    for lbl, seg in [("前半段", d_half1), ("后半段", d_half2)]:            d_seg = strategy_func(seg, params)            m_seg = BacktestEngine.analyze(d_seg)            print(f"  {lbl}: {m_seg['总收益率']} | 年化 {m_seg['年化']} | 夏普 {m_seg['夏普']} | 回撤 {m_seg['最大回撤']}")    return m    @staticmethod    def param_sensitivity(df_prep, strategy_func, strategy_name, param_name, param_values, fixed_params):    """参数敏感性分析"""    print(f"\n📈 敏感性分析 — {strategy_name} [{param_name}]")    print(f"{'参数':>10} {'总收益':>10} {'年化':>10} {'夏普':>7} {'回撤':>10} {'胜率':>6} {'交易':>5}")    print(f"{'-'*10} {'-'*10} {'-'*10} {'-'*7} {'-'*10} {'-'*6} {'-'*5}")    for v in param_values:            p = {**fixed_params, param_name: v}            d = strategy_func(df_prep, p)            m = BacktestEngine.analyze(d)            total = BacktestReport._val(m, '总收益率')            ann = BacktestReport._val(m, '年化')            sh = m.get('夏普', 0)            mdd = m.get('最大回撤', 'N/A')            wr = m.get('胜率(交易)', 'N/A')            trades = m.get('开仓次数', 0)            print(f"{v:>10} {total:>+9.2f}% {ann:>+9.2f}% {sh:>+6.3f} {mdd:>9} {wr:>5} {trades:>4}次")    @staticmethod    def multi_period(df_prep, strategy_func, params, periods):    """多周期回测"""    print(f"\n⏱️ 多周期回测")    print(f"{'时期':<18} {'天数':>5} {'总收益':>10} {'年化':>10} {'夏普':>7} {'回撤':>10} {'胜率':>6}")    print(f"{'-'*18} {'-'*5} {'-'*10} {'-'*10} {'-'*7} {'-'*10} {'-'*6}")    for label, start, end in periods:            seg = df_prep[(df_prep['date'] >= start) & (df_prep['date'] <= end)].reset_index(drop=True)            seg['return'] = seg['close'].pct_change()            if len(seg) < 30:                continue            d = strategy_func(seg, params)            m = BacktestEngine.analyze(d)            total = BacktestReport._val(m, '总收益率')            ann = BacktestReport._val(m, '年化')            sh = m.get('夏普', 0)            mdd = m.get('最大回撤', 'N/A')            wr = m.get('胜率(交易)', 'N/A')            print(f"{label:<18} {len(seg):>5} {total:>+9.2f}% {ann:>+9.2f}% {sh:>+6.3f} {mdd:>9} {wr:>5}")# ==================== 主入口 ====================if __name__ == "__main__":    fetcher = DataFetcher()    bte = BacktestEngine    report = BacktestReport()    param_search = ParamSearch()    mode = sys.argv[1] if len(sys.argv) > 1 else 'brief'    # 获取数据    print("📥 获取数据...")    df1 = fetcher.get('sz000009', 500)    df2 = fetcher.get('sz002332', 500)    if mode == 'brief':    # 快速对比回测（兼容旧版format）    for name, df in [("中国宝安", df1), ("仙琚制药", df2)]:            dp = bte._prepare(df)            report.brief(dp, name)    elif mode == 'full':    full_report = {}    for name, df in [("中国宝安", df1), ("仙琚制药", df2)]:            dp = bte._prepare(df)            # 融合策略完整报告            report.full(dp, name, "融合1: MA14/18+布林中轨+RSI", bte.strat_fusion1, {'stop_loss':0.05})            # 敏感性分析：止损            report.param_sensitivity(dp, bte.strat_fusion1, "融合1", 'stop_loss',                [0, 0.02, 0.03, 0.05, 0.08, 0.10, 0.12, 0.15], {'stop_loss': 0.05})            # 多周期            periods = [                ("全部区间", dp['date'].min(), dp['date'].max()),                ("前半", dp['date'].min(), dp['date'].min() + (dp['date'].max()-dp['date'].min())/2),                ("后半", dp['date'].min() + (dp['date'].max()-dp['date'].min())/2, dp['date'].max()),            ]            report.multi_period(dp, bte.strat_fusion1, {'stop_loss':0.05}, periods)    elif mode == 'scan':    # 全量参数搜索    for name, df in [("中国宝安", df1), ("仙琚制药", df2)]:            dp = bte._prepare(df)            print(f"\n{'='*70}")            print(f"🔍 参数搜索 — {name}")            print(f"{'='*70}")            # MA参数搜索            print(f"\n📈 MA参数搜索 (快5-24, 慢6-39):")            results = []            for f in range(5, 25):                for s in range(f+1, min(f+25, 40)):                    d = bte.strat_ma_cross(dp, {'fast':f, 'slow':s})                    m = bte.analyze(d)                    total = BacktestReport._val(m, '总收益率')                    sh = m.get('夏普', 0)                    if total > 0 and sh > 0:                        results.append((f, s, total, sh, m))            results.sort(key=lambda x: x[2], reverse=True)            print(f"  (共{len(results)}组合带正收益+正夏普)")            print(f"  {'MA快':>5} {'MA慢':>5} {'收益':>10} {'年化':>8} {'夏普':>6} {'回撤':>8} {'胜率':>6} {'交易':>4}")            print(f"  {'-'*55}")            for f, s, total, sh, m in results[:10]:                ann = BacktestReport._val(m, '年化')                mdd = m.get('最大回撤', 'N/A')                wr = m.get('胜率(交易)', 'N/A')                trades = m.get('开仓次数', 0)                print(f"  {f:>5} {s:>5} {total:>+8.2f}% {ann:>+7.2f}% {sh:>+5.3f} {mdd:>7} {wr:>5} {trades:>4}")    elif mode == 'fusion_scan':    # 融合策略参数变体测试    for name, df in [("中国宝安", df1), ("仙琚制药", df2)]:            dp = bte._prepare(df)            print(f"\n{'='*70}")            print(f"🔬 融合策略变体 — {name}")            print(f"{'='*70}")            variants = [                ("融合1: MA14/18+布林中轨+RSI 止损5%", bte.strat_fusion1, {'stop_loss':0.05}),                ("融合1: 止损3%", bte.strat_fusion1, {'stop_loss':0.03}),                ("融合1: 止损8%", bte.strat_fusion1, {'stop_loss':0.08}),                ("融合1: 无止损", bte.strat_fusion1, {'stop_loss':0}),                ("融合2: 布林触底+KDJ 止损5%", bte.strat_fusion2, {'stop_loss':0.05}),                ("融合2: 止损3%", bte.strat_fusion2, {'stop_loss':0.03}),                ("融合2: 止损8%", bte.strat_fusion2, {'stop_loss':0.08}),                ("融合3: 三确认(MA+RSI+BB+MACD)", bte.strat_fusion3, {}),                ("MA14/18金叉 止损5%", bte.strat_ma_cross, {'fast':14,'slow':18,'stop_loss':0.05}),                ("MA14/18金叉 止损3%", bte.strat_ma_cross, {'fast':14,'slow':18,'stop_loss':0.03}),            ]            print(f"{'策略':<32} {'总收益':>8} {'年化':>8} {'夏普':>6} {'回撤':>8} {'胜率':>5} {'交易':>5}")            print(f"{'-'*32} {'-'*8} {'-'*8} {'-'*6} {'-'*8} {'-'*5} {'-'*5}")            for sname, func, params in variants:                d = func(dp, params)                m = bte.analyze(d)                total = BacktestReport._val(m, '总收益率')                ann = BacktestReport._val(m, '年化')                sh = m.get('夏普', 0)                mdd = m.get('最大回撤', 'N/A')                wr = m.get('胜率(交易)', 'N/A')                trades = m.get('开仓次数', 0)                print(f"{sname:<32} {total:>+7.2f}% {ann:>+7.2f}% {sh:>+5.3f} {mdd:>7} {wr:>5} {trades:>4}次")    print(f"\n{'='*70}")    print("✅ 回测完成")